// src/lib/mcp/tools/get-destination-guide.ts
function toText(intro3) {
  if (!intro3) return "";
  if (typeof intro3 === "string") return intro3;
  if (Array.isArray(intro3)) return intro3.join("\n\n");
  if (typeof intro3 === "object") {
    const o = intro3;
    return [o.title, o.description, o.quickTip].filter(Boolean).join("\n\n");
  }
  return "";
}
var get_destination_guide_default = defineTool2({
  name: "get_destination_guide",
  title: "Get destination guide",
  description: "Get the full allergy-friendly guide for one destination by its id (from list_destinations): intro, hotels, restaurants, FAQs, and travel tips.",
  inputSchema: {
    id: z2.string().min(1).describe("Destination id, e.g. 'london', 'paris', 'tuscany'.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ id }) => {
    const key = id.trim().toLowerCase();
    const content = destinationData[key];
    const meta = destinations.find((d) => d.id === key);
    if (!content) {
      return {
        content: [
          {
            type: "text",
            text: `No destination guide found for id "${id}". Use list_destinations to see valid ids.`
          }
        ],
        isError: true
      };
    }
    const guide = {
      id: key,
      name: meta?.name ?? content.title ?? key,
      country: meta?.country,
      intro: toText(content.intro),
      hotels: (content.hotels ?? []).map((h) => ({
        name: h.name,
        description: h.description,
        location: h.location ?? h.address,
        website: h.website ?? h.websiteUrl,
        allergyInfo: h.allergyInfo,
        allergenFriendly: h.allergenFriendly
      })),
      restaurants: (content.restaurants ?? []).map((r) => ({
        name: r.name,
        description: r.description,
        cuisine: r.cuisine,
        location: r.location ?? r.address,
        allergyInfo: r.allergyInfo
      })),
      faqs: content.faqs ?? [],
      travelTips: content.travelTips ?? content.tips ?? []
    };
    return {
      content: [{ type: "text", text: JSON.stringify(guide, null, 2) }],
      structuredContent: { guide }
    };
  }
});

// src/lib/mcp/tools/search-hotels.ts
import { defineTool as defineTool3 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z as z3 } from "npm:zod@^3.25.76";
var search_hotels_default = defineTool3({
  name: "search_hotels",
  title: "Search allergy-friendly hotels",
  description: "Search allergy-friendly hotels across all destination guides by keyword (hotel name, destination, or allergy info). Returns matching hotels with the destination they belong to.",
  inputSchema: {
    query: z3.string().min(1).describe("Keyword, e.g. 'gluten-free London', 'nut-free', or a hotel name."),
    limit: z3.number().int().optional().describe("Max results to return. Defaults to 20.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ query, limit }) => {
    const q = query.trim().toLowerCase();
    const max = Math.max(1, Math.min(limit ?? 20, 50));
    const nameById = new Map(destinations.map((d) => [d.id, d.name]));
    const results = [];
    for (const [id, content] of Object.entries(destinationData)) {
      const destName = nameById.get(id) ?? id;
      for (const h of content.hotels ?? []) {
        const hay = [h.name, h.description, h.allergyInfo, destName, id, (h.allergenFriendly ?? []).join(" ")].filter(Boolean).join(" ").toLowerCase();
        if (hay.includes(q)) {
          results.push({
            name: h.name,
            destination: destName,
            destinationId: id,
            description: h.description,
            website: h.website ?? h.websiteUrl,
            allergyInfo: h.allergyInfo
          });
        }
        if (results.length >= max) break;
      }
      if (results.length >= max) break;
    }
    return {
      content: [{ type: "text", text: JSON.stringify(results, null, 2) }],
      structuredContent: { count: results.length, hotels: results }
    };
  }
});

